import React from 'react';
import './profile.css';
import Image from './phonk_wallpaper.jpg';


function ProfilePage() {
  return(
  <div id="content">
      <div id="info_card">
        <p id="info_card_name">тут типа свежие новости</p>
        <p id="history_card_text">тут типа тоже какие то новости</p>
      </div>
      <div id="friends_card">
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="friends_card_img"></img>
        <p id="friends_card_text">тут типа тоже какие то новости</p>
      </div>
      <div id="history_card">
        <p id="history_card_text">тут типа тоже какие то новости</p>
        <p id="history_card_price">тут типа тоже какие то новости</p>
      </div>
  </div>
  )
}

export default ProfilePage;
